#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""
UTMS Website Admin Tab
Run this in your UTMS-main folder: python add_website_admin.py
"""
import os, base64

BASE = os.path.dirname(os.path.abspath(__file__))

def wb64(path, b64):
    full = os.path.join(BASE, path)
    d = os.path.dirname(full)
    if d: os.makedirs(d, exist_ok=True)
    with open(full, "w", encoding="utf-8") as f:
        f.write(base64.b64decode(b64).decode("utf-8"))
    print(f"  [OK] {path}")

print("\n" + "="*52)
print("  UTMS - Adding Website Admin tab")
print("="*52 + "\n")

# 1. Add template
wb64("templates/owner/website_admin.html", '')

# 2. Add routes to owner.py
owner_path = os.path.join(BASE, "app", "routes", "owner.py")
if os.path.exists(owner_path):
    with open(owner_path, "r", encoding="utf-8") as f:
        c = f.read()
    if "website_admin" not in c:
        c += "\n" + '\n# ══════════════════════════════════════════════════════════════\n#  WEBSITE ADMIN TAB\n# ══════════════════════════════════════════════════════════════\n@bp.route("/website")\ndef website_admin():\n    if not session.get("owner_logged_in"):\n        return redirect(url_for("owner.login_page"))\n    return render_template("owner/website_admin.html", active_page="website_admin")\n\n# ── Proxy endpoints: UTMS calls website Flask API ─────────────\nimport urllib.request\nimport urllib.error\n\nWEBSITE_URL = "http://127.0.0.1:5000"\n\ndef _website_get(path):\n    try:\n        with urllib.request.urlopen(WEBSITE_URL + path, timeout=5) as r:\n            import json\n            return json.loads(r.read())\n    except Exception as e:\n        return {"error": str(e)}\n\ndef _website_post(path, data):\n    try:\n        import json\n        body = json.dumps(data).encode("utf-8")\n        req = urllib.request.Request(WEBSITE_URL + path, data=body, headers={"Content-Type":"application/json"}, method="POST")\n        with urllib.request.urlopen(req, timeout=5) as r:\n            return json.loads(r.read())\n    except Exception as e:\n        return {"error": str(e), "success": False}\n\n@bp.route("/api/website/orders")\ndef wa_orders():\n    data = _website_get("/api/admin/orders")\n    return jsonify(data)\n\n@bp.route("/api/website/fabrics")\ndef wa_fabrics():\n    data = _website_get("/api/fabrics")\n    return jsonify(data)\n\n@bp.route("/api/website/fabrics/add", methods=["POST"])\ndef wa_fab_add():\n    return jsonify(_website_post("/api/admin/fabrics/add", request.json))\n\n@bp.route("/api/website/fabrics/delete/<int:fid>", methods=["POST"])\ndef wa_fab_del(fid):\n    return jsonify(_website_post(f"/api/admin/fabrics/delete/{fid}", {}))\n\n@bp.route("/api/website/prices/save", methods=["POST"])\ndef wa_prices_save():\n    return jsonify(_website_post("/api/admin/prices/save", request.json))\n\n@bp.route("/api/website/settings/save", methods=["POST"])\ndef wa_settings_save():\n    return jsonify(_website_post("/api/admin/settings/save", request.json))\n'
        with open(owner_path, "w", encoding="utf-8") as f:
            f.write(c)
        print("  [OK] app/routes/owner.py (website admin routes added)")
    else:
        print("  [SKIP] owner.py already has website admin")

# 3. Add nav link to base.html
base_path = os.path.join(BASE, "templates", "base.html")
if os.path.exists(base_path):
    with open(base_path, "r", encoding="utf-8") as f:
        c = f.read()
    nav_link = """      <a href="/owner/website" class="nav-link">
        <span class="nav-icon">&#127760;</span><span>Website Admin</span>
      </a>"""
    if "website_admin" not in c and "/owner/website" not in c:
        c = c.replace(
            '<a href="/owner/settings"',
            nav_link + "\n      " + '<a href="/owner/settings"'
        )
        with open(base_path, "w", encoding="utf-8") as f:
            f.write(c)
        print("  [OK] templates/base.html (nav link added)")
    else:
        print("  [SKIP] base.html already has website admin link")

print("\n" + "="*52)
print("  Done! Restart your UTMS server.")
print("  Then look for Website Admin in the owner sidebar.")
print("="*52 + "\n")
